external_knowledge:
- 'rays of the sun' metaphorically refers to solar irradiance and PV generation;
- 'breezes of fortune' is a metaphor for favorable conditions like sunny weather and temperature;
- 'energy thirst' symbolizes the total energy consumption;
- 'rooftops' represents the grid nodes where energy is measured;
- 'active accounts' refers to customers with an 'active' account status;
- 'sun never seems to set' signifies sunny weather conditions;
- 'mercury dances above 20 degrees' metaphorically indicates temperatures above 20 degrees Celsius.

sql:
SELECT DISTINCT name 
FROM customers 
WHERE customer_id IN (SELECT customer_id FROM customer_exports);

SELECT DISTINCT customers.name 
FROM customers 
JOIN customer_imports ON customers.customer_id = customer_imports.customer_id;

SELECT name, account_status, energy_source
FROM customers
ORDER BY name ASC;

SELECT customer_id, SUM(amount) AS total_energy_consumption
FROM customer_imports
GROUP BY customer_id;

